def roman_to_int(value: str) -> int:
    if not isinstance(value, str):
        raise ValueError("Input must be a string")

    # Полная таблица для валидации символов и поддержки вычитательной нотации
    valid_chars = set("IVXLCDM")
    values = {
        'I': 1,
        'V': 5,
        'X': 10,
        'L': 50,
        'C': 100,
        'D': 500,
        'M': 1000
    }

    # Проверка на неизвестные символы
    for char in value:
        if char not in valid_chars:
            raise ValueError(f"Invalid Roman numeral character: {char}")

    total = 0
    i = 0
    while i < len(value):
        # Если это последний символ или текущий >= следующего - просто прибавляем
        if i + 1 == len(value) or values[value[i]] >= values[value[i+1]]:
            total += values[value[i]]
            i += 1
        else:
            # Вычитательная нотация (например, IV, IX)
            total += values[value[i+1]] - values[value[i]]
            i += 2
    return total

